import React from "react";
import { ArrowUpRight, ArrowDownLeft } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function TransactionHistoryScreen({ transactions }) {
  return (
    <div className="p-6 pb-24 animate-fade-in">
      <h1 className="text-2xl font-bold mb-4">Transaction History</h1>
      <div className="space-y-4">
        {transactions.length === 0 ? (
          <p className="text-gray-400">No transactions yet.</p>
        ) : (
          transactions.map((t) => (
            <div
              key={t.id}
              className="flex items-center justify-between bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-md cursor-pointer"
              onClick={() =>
                alert(
                  `Transaction: ${t.title}\nAmount: $${formatCurrency(
                    t.amount
                  )}\nDate: ${t.date}`
                )
              }
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-12 h-12 rounded-full flex items-center justify-center ${
                    t.type === "deposit"
                      ? "bg-emerald-100 text-emerald-600"
                      : "bg-red-100 text-red-600"
                  }`}
                >
                  {t.type === "deposit" ? (
                    <ArrowDownLeft className="w-5 h-5" />
                  ) : (
                    <ArrowUpRight className="w-5 h-5" />
                  )}
                </div>
                <div>
                  <p className="font-semibold text-gray-800">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold ${
                  t.type === "deposit" ? "text-emerald-600" : "text-red-600"
                }`}
              >
                {t.type === "deposit" ? "+" : "-"}${formatCurrency(t.amount)}
              </span>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
